var rhtml = /<|&#?\w+;/;

export function buildFragment( elems, context, scripts, selection, ignored ) {
	var elem, tmp, tag, wrap, attached, j,
		fragment = context.createDocumentFragment(),
		nodes = [],
		i = 0,
		l = elems.length;

	for ( ; i < l; i++ ) {
		elem = elems[ i ];

		if ( elem || elem === 0 ) {

			// Add nodes directly
			if ( toType( elem ) === "object" && ( elem.nodeType || isArrayLike( elem ) ) ) {
				jQuery.merge( nodes, elem.nodeType ? [ elem ] : elem );

			// Convert non-html into a text node
			} else if ( !rhtml.test( elem ) ) {
				nodes.push( context.createTextNode( elem ) );

			// Convert html into DOM nodes
			} else {
				tmp = tmp || fragment.appendChild( context.createElement( "div" ) );

				// Deserialize a standard representation
				tag = ( rtagName.exec( elem ) || [ "", "" ] )[ 1 ].toLowerCase();
				wrap = wrapMap[ tag ] || arr;

				// Create wrappers & descend into them.
				j = wrap.length;
				while ( --j > -1 ) {
					tmp = tmp.appendChild( context.createElement( wrap[ j ] ) );
				}

				tmp.innerHTML = jQuery.htmlPrefilter( elem );

				jQuery.merge( nodes, tmp.childNodes );

				// Remember the top-level container
				tmp = fragment.firstChild;

				// Ensure the created nodes are orphaned (trac-12392)
				tmp.textContent = "";
			}
		}
	}

	// Remove wrapper from fragment
	fragment.textContent = "";

	i = 0;
	while ( ( elem = nodes[ i++ ] ) ) {

		// Skip elements already in the context collection (trac-4087)
		if ( selection && jQuery.inArray( elem, selection ) > -1 ) {
			if ( ignored ) {
				ignored.push( elem );
			}
			continue;
		}

		attached = isAttached( elem );

		// Append to fragment
		tmp = getAll( fragment.appendChild( elem ), "script" );

		// Preserve script evaluation history
		if ( attached ) {
			setGlobalEval( tmp );
		}

		// Capture executables
		if ( scripts ) {
			j = 0;
			while ( ( elem = tmp[ j++ ] ) ) {
				if ( rscriptType.test( elem.type || "" ) ) {
					scripts.push( elem );
				}
			}
		}
	}

	return fragment;
}

'use strict';

const {
  FunctionPrototypeBind,
  Symbol,
} = primordials;

const { codes: {
  ERR_SOCKET_BAD_TYPE,
} } = require('internal/errors');
const { UDP } = internalBinding('udp_wrap');
const { guessHandleType } = require('internal/util');
const {
  isInt32,
  validateFunction,
} = require('internal/validators');
const { UV_EINVAL } = internalBinding('uv');
const kStateSymbol = Symbol('state symbol');
let dns;  // Lazy load for startup performance.


function lookup4(lookup, address, callback) {
  return lookup(address || '127.0.0.1', 4, callback);
}


function lookup6(lookup, address, callback) {
  return lookup(address || '::1', 6, callback);
}

function newHandle(type, lookup) {
  if (lookup === undefined) {
    if (dns === undefined) {
      dns = require('dns');
    }

    lookup = dns.lookup;
  } else {
    validateFunction(lookup, 'lookup');
  }

  if (type === 'udp4') {
    const handle = new UDP();

    handle.lookup = FunctionPrototypeBind(lookup4, handle, lookup);
    return handle;
  }

  if (type === 'udp6') {
    const handle = new UDP();

    handle.lookup = FunctionPrototypeBind(lookup6, handle, lookup);
    handle.bind = handle.bind6;
    handle.connect = handle.connect6;
    handle.send = handle.send6;
    return handle;
  }

  throw new ERR_SOCKET_BAD_TYPE();
}


function _createSocketHandle(address, port, addressType, fd, flags) {
  const handle = newHandle(addressType);
  let err;

  if (isInt32(fd) && fd > 0) {
    const type = guessHandleType(fd);
    if (type !== 'UDP') {
      err = UV_EINVAL;
    } else {
      err = handle.open(fd);
    }
  } else if (port || address) {
    err = handle.bind(address, port || 0, flags);
  }

  if (err) {
    handle.close();
    return err;
  }

  return handle;
}


module.exports = {
  kStateSymbol,
  _createSocketHandle,
  newHandle,
};

'use strict';
const {
  ArrayPrototypeMap,
  Symbol,
  Uint8Array,
} = primordials;
const {
  kUpdateTimer,
  onStreamRead,
} = require('internal/stream_base_commons');
const { owner_symbol } = require('internal/async_hooks').symbols;
const { Readable } = require('stream');
const {
  validateObject,
  validateBoolean,
  validateFunction,
} = require('internal/validators');
const {
  codes: {
    ERR_INVALID_ARG_VALUE,
  },
} = require('internal/errors');
const { kEmptyObject, emitExperimentalWarning } = require('internal/util');
const {
  queryObjects: _queryObjects,
} = internalBinding('internal_only_v8');
const {
  inspect,
} = require('internal/util/inspect');
const kHandle = Symbol('kHandle');

function getHeapSnapshotOptions(options = kEmptyObject) {
  validateObject(options, 'options');
  const {
    exposeInternals = false,
    exposeNumericValues = false,
  } = options;
  validateBoolean(exposeInternals, 'options.exposeInternals');
  validateBoolean(exposeNumericValues, 'options.exposeNumericValues');
  return new Uint8Array([+exposeInternals, +exposeNumericValues]);
}

class HeapSnapshotStream extends Readable {
  constructor(handle) {
    super({ autoDestroy: true });
    this[kHandle] = handle;
    handle[owner_symbol] = this;
    handle.onread = onStreamRead;
  }

  _read() {
    if (this[kHandle])
      this[kHandle].readStart();
  }

  _destroy(err, callback) {
    // Release the references on the handle so that
    // it can be garbage collected.
    this[kHandle][owner_symbol] = undefined;
    this[kHandle] = undefined;
    callback(err);
  }

  [kUpdateTimer]() {
    // Does nothing
  }
}

const inspectOptions = {
  __proto__: null,
  depth: 0,
};
function queryObjects(ctor, options = kEmptyObject) {
  validateFunction(ctor, 'constructor');
  if (options !== kEmptyObject) {
    validateObject(options, 'options');
  }
  const format = options.format || 'count';
  if (format !== 'count' && format !== 'summary') {
    throw new ERR_INVALID_ARG_VALUE('options.format', format);
  }
  emitExperimentalWarning('v8.queryObjects()');
  // Matching the console API behavior - just access the .prototype.
  const objects = _queryObjects(ctor.prototype);
  if (format === 'count') {
    return objects.length;
  }
  // options.format is 'summary'.
  return ArrayPrototypeMap(objects, (object) => inspect(object, inspectOptions));
}

module.exports = {
  getHeapSnapshotOptions,
  HeapSnapshotStream,
  queryObjects,
};

const MESSAGE_ID_UNIQUE = "unique";
const MESSAGE_ID_CONFLICTING = "conflicting";

const conflictingFlags = [
  ["Leading", "Trailing", "Dangling"],
  ["Block", "Line"],
];

const isCommentCheckFlags = (node) =>
  node.type === "MemberExpression" &&
  !node.computed &&
  !node.optional &&
  node.object.type === "Identifier" &&
  node.object.name === "CommentCheckFlags" &&
  node.property.type === "Identifier";

const flatFlags = (node) => {
  const flags = [];
  const binaryExpressions = [node];
  while (binaryExpressions.length > 0) {
    const { left, right } = binaryExpressions.shift();
    for (const node of [left, right]) {
      if (node.type === "BinaryExpression" && node.operator === "|") {
        binaryExpressions.push(node);
        continue;
      }

      if (!isCommentCheckFlags(node)) {
        return [];
      }

      flags.push(node);
    }
  }

  return flags.map((node) => node.property.name);
};

export default {
  meta: {
    type: "suggestion",
    messages: {
      [MESSAGE_ID_UNIQUE]: "Do not use same flag multiple times.",
      [MESSAGE_ID_CONFLICTING]: "Do not use {{flags}} together.",
    },
  },
  create(context) {
    return {
      ':not(BinaryExpression) > BinaryExpression[operator="|"]'(node) {
        const flags = flatFlags(node);

        if (flags.length < 2) {
          return;
        }

        const uniqueFlags = new Set(flags);
        if (uniqueFlags.size !== flags.length) {
          context.report({
            node,
            messageId: MESSAGE_ID_UNIQUE,
          });
          return;
        }

        for (const group of conflictingFlags) {
          const presentFlags = group.filter((flag) => uniqueFlags.has(flag));
          if (presentFlags.length > 1) {
            context.report({
              node,
              messageId: MESSAGE_ID_CONFLICTING,
              data: {
                flags: presentFlags
                  .map((flag) => `'CommentCheckFlags.${flag}'`)
                  .join(", "),
              },
            });
          }
        }
      },
    };
  },
};

import mockable from "./mockable.js";
import { picocolors } from "./prettier-internal.js";

const { argv, env } = process;
// https://github.com/alexeyraspopov/picocolors/blob/0e7c4af2de299dd7bc5916f2bddd151fa2f66740/picocolors.js#L2
// Not working on Windows, but this is how `picocolors` works for stdout, let's keep it this way for now
const isStderrColorSupported =
  !(Boolean(env.NO_COLOR) || argv.includes("--no-color")) &&
  (Boolean(env.FORCE_COLOR) ||
    argv.includes("--color") ||
    process.platform === "win32" ||
    (process.stderr.isTTY && env.TERM !== "dumb") ||
    Boolean(env.CI));
// To test this feature,
// run `echo foo | node bin/prettier --unknown-flag --log-level=debug 2>error.log`
// open error.log check if `[warn]` or `[debug]` is colored
// https://github.com/prettier/prettier/issues/13097
const picocolorsStderr = picocolors.createColors(isStderrColorSupported);

const emptyLogResult = { clear() {} };
function createLogger(logLevel = "log") {
  return {
    logLevel,
    warn: createLogFunc("warn", "yellow"),
    error: createLogFunc("error", "red"),
    debug: createLogFunc("debug", "blue"),
    log: createLogFunc("log"),
  };

  function createLogFunc(loggerName, color) {
    if (!shouldLog(loggerName)) {
      return () => emptyLogResult;
    }

    const stream = process[loggerName === "log" ? "stdout" : "stderr"];
    const colors = loggerName === "log" ? picocolors : picocolorsStderr;
    const prefix = color ? `[${colors[color](loggerName)}] ` : "";

    return (message, options) => {
      options = {
        newline: true,
        clearable: false,
        ...options,
      };
      message =
        message.replaceAll(/^/gm, prefix) + (options.newline ? "\n" : "");
      stream.write(message);

      if (options.clearable) {
        return {
          clear: () => mockable.clearStreamText(stream, message),
        };
      }
    };
  }

  function shouldLog(loggerName) {
    switch (logLevel) {
      case "silent":
        return false;
      case "debug":
        if (loggerName === "debug") {
          return true;
        }
      // fall through
      case "log":
        if (loggerName === "log") {
          return true;
        }
      // fall through
      case "warn":
        if (loggerName === "warn") {
          return true;
        }
      // fall through
      case "error":
        return loggerName === "error";
    }
  }
}

export default createLogger;

import { hooks } from '../utils/hooks';
import isUndefined from '../utils/is-undefined';
import getParsingFlags from '../create/parsing-flags';

// Plugins that add properties should also add the key here (null value),
// so we can properly clone ourselves.
var momentProperties = (hooks.momentProperties = []),
    updateInProgress = false;

export function copyConfig(to, from) {
    var i,
        prop,
        val,
        momentPropertiesLen = momentProperties.length;

    if (!isUndefined(from._isAMomentObject)) {
        to._isAMomentObject = from._isAMomentObject;
    }
    if (!isUndefined(from._i)) {
        to._i = from._i;
    }
    if (!isUndefined(from._f)) {
        to._f = from._f;
    }
    if (!isUndefined(from._l)) {
        to._l = from._l;
    }
    if (!isUndefined(from._strict)) {
        to._strict = from._strict;
    }
    if (!isUndefined(from._tzm)) {
        to._tzm = from._tzm;
    }
    if (!isUndefined(from._isUTC)) {
        to._isUTC = from._isUTC;
    }
    if (!isUndefined(from._offset)) {
        to._offset = from._offset;
    }
    if (!isUndefined(from._pf)) {
        to._pf = getParsingFlags(from);
    }
    if (!isUndefined(from._locale)) {
        to._locale = from._locale;
    }

    if (momentPropertiesLen > 0) {
        for (i = 0; i < momentPropertiesLen; i++) {
            prop = momentProperties[i];
            val = from[prop];
            if (!isUndefined(val)) {
                to[prop] = val;
            }
        }
    }

    return to;
}

// Moment prototype object
export function Moment(config) {
    copyConfig(this, config);
    this._d = new Date(config._d != null ? config._d.getTime() : NaN);
    if (!this.isValid()) {
        this._d = new Date(NaN);
    }
    // Prevent infinite loop in case updateOffset creates new moment
    // objects.
    if (updateInProgress === false) {
        updateInProgress = true;
        hooks.updateOffset(this);
        updateInProgress = false;
    }
}

export function isMoment(obj) {
    return (
        obj instanceof Moment || (obj != null && obj._isAMomentObject != null)
    );
}

'use strict';

const { Storage } = internalBinding('webstorage');
const { DOMStorage } = require('inspector');
const path = require('path');
const { getOptionValue } = require('internal/options');

class InspectorLocalStorage extends Storage {
  setItem(key, value) {
    key = `${key}`;
    value = `${value}`;
    const oldValue = this.getItem(key);
    super.setItem(key, value);
    if (oldValue == null) {
      itemAdded(key, value, true);
    } else {
      itemUpdated(key, oldValue, value, true);
    }
  }

  removeItem(key) {
    key = `${key}`;
    super.removeItem(key);
    itemRemoved(key, true);
  }

  clear() {
    super.clear();
    itemsCleared(true);
  }
}

const InspectorSessionStorage = class extends Storage {
  setItem(key, value) {
    key = `${key}`;
    value = `${value}`;
    const oldValue = this.getItem(key);
    super.setItem(key, value);
    if (oldValue == null) {
      itemAdded(key, value, false);
    } else {
      itemUpdated(key, oldValue, value, false);
    }
  }

  removeItem(key) {
    key = `${key}`;
    super.removeItem(key);
    itemRemoved(key, false);
  }

  clear() {
    super.clear();
    itemsCleared(false);
  }
};

function itemAdded(key, value, isLocalStorage) {
  DOMStorage.domStorageItemAdded({
    key,
    newValue: value,
    storageId: {
      securityOrigin: '',
      isLocalStorage,
      storageKey: getStorageKey(),
    },
  });
}

function itemUpdated(key, oldValue, newValue, isLocalStorage) {
  DOMStorage.domStorageItemUpdated({
    key,
    oldValue,
    newValue,
    storageId: {
      securityOrigin: '',
      isLocalStorage,
      storageKey: getStorageKey(),
    },
  });
}

function itemRemoved(key, isLocalStorage) {
  DOMStorage.domStorageItemRemoved({
    key,
    storageId: {
      securityOrigin: '',
      isLocalStorage,
      storageKey: getStorageKey(),
    },
  });
}

function itemsCleared(isLocalStorage) {
  DOMStorage.domStorageItemsCleared({
    storageId: {
      securityOrigin: '',
      isLocalStorage,
      storageKey: getStorageKey(),
    },
  });
}

function getStorageKey() {
  const localStorageFile = getOptionValue('--localstorage-file');
  const resolvedAbsolutePath = path.resolve(localStorageFile);
  return 'file://' + resolvedAbsolutePath;
}

module.exports = {
  InspectorLocalStorage,
  InspectorSessionStorage,
};

import path from "node:path";

// `node.comments`
const memberExpressionSelector = [
  "MemberExpression[computed=false]",
  "",
  ">",
  "Identifier.property",
  '[name="comments"]',
].join("");

// `const {comments} = node`
// `const {comments: nodeComments} = node`
const objectPatternSelector = [
  "ObjectPattern",
  ">",
  "Property.properties",
  ">",
  "Identifier.key",
  '[name="comments"]',
].join("");

const selector = `:matches(${memberExpressionSelector}, ${objectPatternSelector})`;

const messageId = "no-node-comments";

export default {
  meta: {
    type: "suggestion",
    messages: {
      [messageId]: "Do not access node.comments.",
    },
    schema: {
      type: "array",
      items: {
        anyOf: [
          { type: "string" },
          {
            type: "object",
            properties: {
              file: { type: "string" },
              functions: {
                type: "array",
                items: { type: "string" },
              },
            },
          },
        ],
      },
    },
  },
  create(context) {
    const { physicalFilename: fileName } = context;
    const ignored = new Map(
      context.options.map((option) => {
        if (typeof option === "string") {
          option = { file: option };
        }
        const { file, functions } = option;
        return [
          path.join(import.meta.dirname, "../../..", file),
          functions ? new Set(functions) : true,
        ];
      }),
    );
    // avoid report on `const {comments} = node` twice
    const reported = new Set();
    return {
      [selector](node) {
        if (reported.has(node)) {
          return;
        }

        if (ignored.has(fileName)) {
          const functionNames = ignored.get(fileName);
          if (functionNames === true) {
            return;
          }
          let isIgnored;
          let currentNode = node.parent;
          while (currentNode) {
            if (
              currentNode.type === "FunctionDeclaration" &&
              currentNode.id &&
              currentNode.id.type === "Identifier" &&
              functionNames.has(currentNode.id.name)
            ) {
              isIgnored = true;
              break;
            }
            currentNode = currentNode.parent;
          }
          if (isIgnored) {
            return;
          }
        }
        reported.add(node);
        context.report({
          node,
          messageId,
        });
      },
    };
  },
};

